use minixrs_kernel_shared::endpoint::{Endpoint, ProcNr};

/// Table capacity. Slots `0..NR_BOOT_PROCS + NR_STUB_PROCS` (= 16) are seeded
/// at init; the pool above that ([`FORK_POOL_BASE`]`..NR_MPROCS`) is where 4.6's
/// fork allocates children.
pub const NR_MPROCS: usize = 32;

/// First slot fork may allocate. Boot servers + demo stubs own `[0, 16)`; forked
/// children land in `[FORK_POOL_BASE, NR_MPROCS)`. A child's slot index is also
/// its kernel proc number, so this range must stay within the kernel proc table
/// and within VM's `MAX_CLIENTS` region-table cap (both hold).
pub const FORK_POOL_BASE: usize = NR_BOOT_PROCS + NR_STUB_PROCS;

/// Entry holds a live process.
pub const MF_IN_USE: u8 = 1 << 0;
/// Boot system process — the kill path refuses to terminate it.
pub const MF_PRIV_PROC: u8 = 1 << 1;
/// Terminated (a zombie): the process is gone at the kernel level (`SYS_EXIT`
/// ran) but its `mproc` slot is retained — holding the exit status — until its
/// parent `wait()`s and reaps it. Set by both the exit path ([`set_zombie_in`],
/// with a real status) and the kill path ([`handle_kill_in`]).
pub const MF_DEAD: u8 = 1 << 2;
/// This process is a parent blocked in `wait()` with no reapable child yet;
/// when a child exits, [`set_zombie_in`]'s caller wakes it directly.
pub const MF_WAITING: u8 = 1 << 3;

/// One `mproc` entry. The slot index *is* the kernel proc number, but once slots
/// recycle (4.6 fork/exit bump the endpoint generation) `boot_endpoint(slot)` no
/// longer identifies the occupant, so the generation-aware endpoint is stored
/// explicitly.
#[derive(Clone, Copy)]
pub struct MProc {
    pub pid: i32,
    pub parent_slot: usize,
    /// Generation-aware endpoint of this process (from `SYS_FORK` for children,
    /// `boot_endpoint(slot)` for seeded boot/stub procs).
    pub endpoint: Endpoint,
    /// Encoded exit status stored while the process is a zombie (`MF_DEAD`).
    pub exit_status: i32,
    pub flags: u8,
}

impl MProc {
    pub const EMPTY: Self = Self {
        pid: 0,
        parent_slot: 0,
        endpoint: 0,
        exit_status: 0,
        flags: 0,
    };
}

/// Disposition of a kill request against a slot.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum KillAction {
    /// Ordinary user process: caller should terminate it (`SYS_EXIT`).
    Terminate,
    /// Boot system process: refuse — sig2mess is a later slice.
    SkipPrivileged,
    /// Unknown, unused, or already-dead slot: nothing to do.
    NotFound,
}

/// Seed the table with the boot image + demo stubs. Pure; called once from
/// PM's SEF init via [`seed`].
fn seed_in(t: &mut [MProc; NR_MPROCS]) {
    let pm = PM_PROC_NR.get() as usize;
    let rs = RS_PROC_NR.get() as usize;
    let init = INIT_PROC_NR.get() as usize;

    // Every seeded proc is at generation 0, so its endpoint is `boot_endpoint`
    // of its slot (= kernel proc number). Forked children later store the
    // generation-aware endpoint `SYS_FORK` hands back.
    let ep = |slot: usize| boot_endpoint(ProcNr::new(slot as i32));

    // PM: pid 0, its own parent (MINIX `pm_init` patches itself the same way).
    t[pm] = MProc {
        pid: 0,
        parent_slot: pm,
        endpoint: ep(pm),
        exit_status: 0,
        flags: MF_IN_USE | MF_PRIV_PROC,
    };
    // INIT: pid 1. Not running yet (no ELF until 4.8) but seeded so the demo
    // stubs have a parent with a pid.
    t[init] = MProc {
        pid: 1,
        parent_slot: rs,
        endpoint: ep(init),
        exit_status: 0,
        flags: MF_IN_USE | MF_PRIV_PROC,
    };

    // Remaining boot servers: next free pids in slot order, parented to RS
    // (the root system process) — except RS itself, parented to PM so no
    // process is its own ancestor besides PM.
    let mut next_pid = 2;
    for (slot, e) in t.iter_mut().enumerate().take(NR_BOOT_PROCS) {
        if slot == pm || slot == init {
            continue;
        }
        *e = MProc {
            pid: next_pid,
            parent_slot: if slot == rs { pm } else { rs },
            endpoint: ep(slot),
            exit_status: 0,
            flags: MF_IN_USE | MF_PRIV_PROC,
        };
        next_pid += 1;
    }

    // Demo stubs: ordinary user processes, parented to INIT, pids continuing
    // past the servers (slots 11..=15 land on pids 11..=15).
    for (slot, e) in t
        .iter_mut()
        .enumerate()
        .skip(NR_BOOT_PROCS)
        .take(NR_STUB_PROCS)
    {
        *e = MProc {
            pid: next_pid,
            parent_slot: init,
            endpoint: ep(slot),
            exit_status: 0,
            flags: MF_IN_USE,
        };
        next_pid += 1;
    }
}

pub unsafe fn userland_bootstrap() {
    // 1. Verify Limine left MAIR_EL1 + TCR_EL1 in the shape our walker
    //    + per-proc TTBR0 install expect. The slice-3.1b TCR_EL1.AS = 0
    //    assert was added inside `assert_tcr_el1_ttbr0_ready`.
    mmu::assert_mair_normal_wb();
    mmu::assert_tcr_el1_ttbr0_ready();

    // 2. Clear TCR_EL1.EPD0 once. Per-proc TTBR0 install happens at every
    //    context switch via `proc::sched::schedule_next`.
    // SAFETY: DAIF still masked from Limine handoff; single-threaded boot.
    unsafe { mmu::enable_ttbr0_walks_once() };

    // 2.5. Load every boot server from the embedded MXBI archive (slice 4.2).
    //      VM is packed first so it takes ASID 1 and is enqueued first; its
    //      `RECEIVE(ANY)` blocks immediately (no senders yet), leaving the run
    //      queue free for the band-8 stubs. Each server's proc/priv slot was
    //      already populated by `proc::init` → `init_boot_image`; this fills in
    //      the address space + EL0 entry state, clears RTS_NO_PRIV, and enqueues.
    // SAFETY: single-threaded boot; sole writer of each server's proc slot + the
    // frame allocator.
    unsafe {
        let image = crate::boot_image::BootImage::get();
        for (nr, elf) in image.iter() {
            // A negative proc-nr (`com::EXEC_ONLY_PROC_NR`) tags an archive
            // module that is not a boot server — it is packed only so
            // `SYS_EXEC` can resolve it by name (slice 4.7's `worker`), and it
            // has no proc/priv slot to load into. Skip it.
            if nr.get() < 0 {
                continue;
            }
            load_boot_server(nr, elf);
        }
    }

    // 3. Build each stub. Sequential calls — each build_stub allocates
    //    fresh frames + a fresh AddrSpace and writes its proc slot.
    // SAFETY: single-threaded boot; build_stub only touches its own
    // allocated state + the named proc slot.
    unsafe {
        build_stub(
            STUB_A_PROC_NR,
            Some(STUB_A_PRIV_ID),
            b'A',
            &_user_stub_a_start,
            &_user_stub_a_end,
            USER_CODE_VA_A,
            USER_STACK_VA_A,
            HeapWindow::EMPTY,
            false,
        );
        build_stub(
            STUB_B_PROC_NR,
            Some(STUB_B_PRIV_ID),
            b'B',
            &_user_stub_b_start,
            &_user_stub_b_end,
            USER_CODE_VA_B,
            USER_STACK_VA_B,
            HeapWindow::EMPTY,
            false,
        );
        build_stub(
            STUB_C_PROC_NR,
            Some(STUB_C_PRIV_ID),
            b'C',
            &_user_stub_c_start,
            &_user_stub_c_end,
            USER_CODE_VA_C,
            USER_STACK_VA_C,
            HeapWindow::EMPTY,
            false,
        );
        build_stub(
            STUB_D_PROC_NR,
            Some(STUB_D_PRIV_ID),
            b'D',
            &_user_stub_d_start,
            &_user_stub_d_end,
            USER_CODE_VA_D,
            USER_STACK_VA_D,
            // D issues `VM_BRK` to grow its heap and touches it (slice 3.5),
            // then `VM_MMAP`/`VM_MUNMAP` an anonymous region (slice 3.6). Faults
            // route to the VM server, which gates them on its region table. The
            // kernel `heap_window` fast path stays unused, so EMPTY.
            HeapWindow::EMPTY,
            false,
        );
        // Stub E is built *frozen* (slice 4.5): full address space, but no
        // priv slot and RTS_NO_PRIV set — the state a forked child holds. PM's
        // SEF init points it at the shared USER priv and releases it via
        // `SYS_PRIVCTL(PRIVCTL_SET_USER)`; only then does E start its fork loop
        // (child execs the `worker` binary, parent `wait`s and reaps — 4.6b/4.7).
        build_stub(
            STUB_E_PROC_NR,
            None,
            b'E',
            &_user_stub_e_start,
            &_user_stub_e_end,
            USER_CODE_VA_E,
            USER_STACK_VA_E,
            HeapWindow::EMPTY,
            true,
        );
    }

    // 3.5. Pre-delegate stub C to the user-space SCHED server (slice 4.3). C is
    //      a CPU-bound SYS_GETINFO loop, so it regularly exhausts its quantum,
    //      exercising the kernel → SCHED `SCHEDULING_NO_QUANTUM` → `SYS_SCHEDULE`
    //      round-trip. Every other proc stays kernel-scheduled (`scheduler ==
    //      NONE`), including SCHED itself (a scheduler must not schedule itself).
    //      This stands in for the `SCHEDULING_START` a real RS/PM will issue once
    //      they exist (slice 4.5/4.6); until then the kernel claims C directly.
    // SAFETY: single-threaded boot; sole borrow of stub C's slot.
    unsafe {
        let p = proc_slot_mut(STUB_C_PROC_NR).expect("stub C proc slot in range");
        p.scheduler = boot_endpoint(SCHED_PROC_NR);
    }

    // 4. Install priv slots — unchanged from slice 2.6.
    // SAFETY: single-threaded boot; sequential mutable borrows on
    // priv-table slots 16, 17, 18.
    unsafe { install_stub_privs() };

    // 5. Enqueue the runnable stubs. E is *not* enqueued — it sits frozen on
    //    RTS_NO_PRIV until PM's `SYS_PRIVCTL(PRIVCTL_SET_USER)` releases it
    //    (rts_unset enqueues it then).
    // SAFETY: single-threaded boot; no other PROC_TABLE / RUNQ borrows
    // live at this point.
    unsafe {
        sched::enqueue(STUB_A_PROC_NR);
        sched::enqueue(STUB_B_PROC_NR);
        sched::enqueue(STUB_C_PROC_NR);
        sched::enqueue(STUB_D_PROC_NR);
    }

    // 6. One-shot diagnostic: dump per-proc (ttbr0_pa, asid) so the
    //    boot log proves each stub has its own distinct AS.
    //    SAFETY: single-threaded boot; read-only.
    unsafe { print_addrspace_summary() };
}

