36	    RS_PROC_NR, SCHED_PROC_NR, STUB_A_PROC_NR, STUB_B_PROC_NR, STUB_C_PROC_NR, STUB_D_PROC_NR,
37	    STUB_E_PROC_NR, SYSTEM, VM_PROC_NR, boot_endpoint,
38	};
39	use minixrs_kernel_shared::{PrivId, ProcNr};
40	
