42	use crate::arch::aarch64::asid::alloc_asid;
43	use crate::arch::aarch64::mmu::{self, PAGE_SIZE, flush_icache_range};
44	use crate::mm::{Frame, alloc_frame, free_frame, phys_to_hhdm};
45	use crate::proc::bitmap::{set_call_bit, set_sys_bit};
46	use crate::proc::flags::{BILLABLE, PREEMPTIBLE, RTS_NO_PRIV, SRV_T, SYS_PROC, USR_T};
47	use crate::proc::sched;
48	use crate::proc::table::{priv_slot_mut, proc_index, proc_slot_mut, proc_table_ref};
49	use crate::proc::{HeapWindow, Priv, Proc};
50	
51	// ----- EL0 virtual addresses ------------------------------------------------
52	
53	/// VA at which stub A's code page is mapped.
54	pub const USER_CODE_VA_A: u64 = 0x0040_0000; // 4 MiB
55	/// VA at which stub A's stack page is mapped.
56	pub const USER_STACK_VA_A: u64 = 0x0080_0000; // 8 MiB
57	
58	/// VA at which stub B's code page is mapped.
59	pub const USER_CODE_VA_B: u64 = 0x0041_0000;
60	/// VA at which stub B's stack page is mapped.
61	pub const USER_STACK_VA_B: u64 = 0x0081_0000;
62	
63	/// VA at which stub C's code page is mapped.
64	pub const USER_CODE_VA_C: u64 = 0x0042_0000;
65	/// VA at which stub C's stack page is mapped.
66	pub const USER_STACK_VA_C: u64 = 0x0082_0000;
67	
68	/// VA at which stub D's code page is mapped.
69	pub const USER_CODE_VA_D: u64 = 0x0043_0000;
70	/// VA at which stub D's stack page is mapped.
71	pub const USER_STACK_VA_D: u64 = 0x0083_0000;
72	
73	/// VA at which stub E's code page is mapped.
74	pub const USER_CODE_VA_E: u64 = 0x0044_0000;
75	/// VA at which stub E's stack page is mapped.
76	pub const USER_STACK_VA_E: u64 = 0x0084_0000;
77	
78	// Stub D's heap VA (`0x0100_0000`) lives only in `user_stub.S`'s stub D blob
